/**
 * Multiplayer — HTTP Server
 *
 * AUTO-GENERATED by Phoenix VCS
 * Provides health check, metrics, and module endpoints.
 */

import { createServer, IncomingMessage, ServerResponse } from 'node:http';

import * as gameRooms from './game-rooms.js';
import * as matchmaking from './matchmaking.js';
import * as playerManagement from './player-management.js';
import * as realTimeCommunication from './real-time-communication.js';

// ─── Metrics ─────────────────────────────────────────────────────────────────

const metrics = {
  requests_total: 0,
  requests_by_path: {} as Record<string, number>,
  errors_total: 0,
  uptime_start: Date.now(),
};

// ─── Module Registry ─────────────────────────────────────────────────────────

const modules = {
  'game-rooms': gameRooms,
  'matchmaking': matchmaking,
  'player-management': playerManagement,
  'real-time-communication': realTimeCommunication,
};

// ─── Router ──────────────────────────────────────────────────────────────────

type Handler = (req: IncomingMessage, res: ServerResponse) => void | Promise<void>;

const routes: Record<string, Handler> = {
  '/health': (_req, res) => {
    res.writeHead(200, { 'Content-Type': 'application/json' });
    res.end(JSON.stringify({
      status: 'ok',
      service: 'Multiplayer',
      uptime: Math.floor((Date.now() - metrics.uptime_start) / 1000),
      modules: Object.keys(modules),
    }));
  },

  '/metrics': (_req, res) => {
    res.writeHead(200, { 'Content-Type': 'application/json' });
    res.end(JSON.stringify({
      ...metrics,
      uptime_seconds: Math.floor((Date.now() - metrics.uptime_start) / 1000),
    }, null, 2));
  },

  '/modules': (_req, res) => {
    const info = Object.entries(modules).map(([name, mod]) => {
      const phoenix = (mod as Record<string, unknown>)._phoenix as Record<string, unknown> | undefined;
      return {
        name,
        risk_tier: phoenix?.risk_tier ?? 'unknown',
        exports: Object.keys(mod).filter(k => k !== '_phoenix'),
      };
    });
    res.writeHead(200, { 'Content-Type': 'application/json' });
    res.end(JSON.stringify(info, null, 2));
  },
};

// ─── Server ──────────────────────────────────────────────────────────────────

function handleRequest(req: IncomingMessage, res: ServerResponse): void {
  const url = req.url ?? '/';
  const path = url.split('?')[0];

  metrics.requests_total++;
  metrics.requests_by_path[path] = (metrics.requests_by_path[path] ?? 0) + 1;

  const handler = routes[path];
  if (handler) {
    try {
      handler(req, res);
    } catch (err) {
      metrics.errors_total++;
      res.writeHead(500, { 'Content-Type': 'application/json' });
      res.end(JSON.stringify({ error: String(err) }));
    }
  } else {
    res.writeHead(404, { 'Content-Type': 'application/json' });
    res.end(JSON.stringify({
      error: 'Not Found',
      path,
      available: Object.keys(routes),
    }));
  }
}

export function startServer(port?: number): { server: ReturnType<typeof createServer>; port: number; ready: Promise<void> } {
  const requestedPort = port ?? parseInt(process.env.MULTIPLAYER_PORT ?? process.env.PORT ?? '3001', 10);
  const server = createServer(handleRequest);
  let actualPort = requestedPort;

  const ready = new Promise<void>(resolve => {
    server.listen(requestedPort, () => {
      const addr = server.address();
      if (addr && typeof addr === 'object') actualPort = addr.port;
      result.port = actualPort;
      console.log(`Multiplayer listening on http://localhost:${actualPort}`);
      console.log(`  /health   — health check`);
      console.log(`  /metrics  — request metrics`);
      console.log(`  /modules  — registered modules`);
      resolve();
    });
  });

  const result = { server, port: actualPort, ready };
  return result;
}

// Start when run directly
const isMain = process.argv[1]?.endsWith('/multiplayer/server.js') ||
               process.argv[1]?.endsWith('/multiplayer/server.ts');
if (isMain) {
  startServer();
}
